package chi

import "net/http"

// setPathValue sets the path values for the request based on the chi
// route context's URL parameters so that r.PathValue behaves as an
// alias for chi.URLParam on Go 1.22 and later.
func setPathValue(rctx *Context, r *http.Request) {
	for i, key := range rctx.URLParams.Keys {
		value := rctx.URLParams.Values[i]
		r.SetPathValue(key, value)
	}
}
"}

