import (
	"context"
	"net/http"
	"time"
)

// RouteMetric carries the information gathered about a single routed
// request: the matched route pattern, the HTTP method, the request path,
// how long the handler took to run, and the URL parameters extracted
// during routing.
type RouteMetric struct {
	Pattern  string
	Method   string
	Path     string
	Duration time.Duration
	Params   map[string]string
}

// MetricsCollector is notified once a request has been routed to a
// handler and that handler has finished serving the request.
type MetricsCollector interface {
	// RecordHit is called with the context and request that were routed,
	// along with how long the matched handler took to serve it.
	RecordHit(ctx context.Context, r *http.Request, duration time.Duration)
}

// SimpleMetricsCollector is a MetricsCollector that forwards each hit to a
// user-supplied callback as a RouteMetric, for basic metric collection
// scenarios that don't need a full MetricsCollector implementation.
type SimpleMetricsCollector struct {
	Callback func(RouteMetric)
}

// RecordHit implements MetricsCollector.
func (c *SimpleMetricsCollector) RecordHit(ctx context.Context, r *http.Request, duration time.Duration) {
	if c.Callback == nil {
		return
	}

	metric := RouteMetric{
		Method:   r.Method,
		Path:     r.URL.Path,
		Duration: duration,
	}

	if rctx := RouteContext(ctx); rctx != nil {
		metric.Pattern = rctx.RoutePattern()
		if n := len(rctx.URLParams.Keys); n > 0 {
			metric.Params = make(map[string]string, n)
			for i, key := range rctx.URLParams.Keys {
				metric.Params[key] = rctx.URLParams.Values[i]
			}
		}
	}

	c.Callback(metric)
}
"}

