package scratch

import (
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/go-chi/chi/v5"
)

func TestPathValueAndMetrics(t *testing.T) {
	r := chi.NewRouter()

	var got chi.RouteMetric
	r.SetMetricsCollector(&chi.SimpleMetricsCollector{
		Callback: func(m chi.RouteMetric) {
			got = m
		},
	})

	r.Get("/b/{bucket}", func(w http.ResponseWriter, req *http.Request) {
		time.Sleep(5 * time.Millisecond)
		w.Write([]byte(chi.URLParam(req, "bucket")))
	})

	ts := httptest.NewServer(r)
	defer ts.Close()

	resp, err := http.Get(ts.URL + "/b/mybucket")
	if err != nil {
		t.Fatal(err)
	}
	defer resp.Body.Close()

	if got.Pattern != "/b/{bucket}" {
		t.Fatalf("expected pattern /b/{bucket}, got %q", got.Pattern)
	}
	if got.Method != "GET" {
		t.Fatalf("expected method GET, got %q", got.Method)
	}
	if got.Duration < 5*time.Millisecond {
		t.Fatalf("expected duration >= 5ms, got %v", got.Duration)
	}
	if got.Params["bucket"] != "mybucket" {
		t.Fatalf("expected param bucket=mybucket, got %v", got.Params)
	}
	t.Logf("metric: %+v", got)
}
EOF
